module RefModule(  
    input D,  
    input CLK,  
    output reg Q,  
    output reg Qn  
);  
    reg master;  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin  
        master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= master;  
        Qn <= ~master;  
    end  
endmodule
